  1â†’import ThumbUpIcon from '@airlock/material-symbols/svg/outlined/recommend.svg';
  2â†’import React, { useEffect, useRef } from 'react';
  3â†’import { Trans, useTranslation } from 'react-i18next';
  4â†’import { useNavigate } from 'react-router';
  5â†’
  6â†’import useTenant from '@airlock-cloud/management-ui/common/use-tenant/useTenant';
  7â†’import { InfoZone } from '@airlock-cloud/management-ui/components/info-zone';
  8â†’import { EmbeddedLink } from '@airlock-cloud/management-ui/components/link/Link';
  9â†’import { Page } from '@airlock-cloud/management-ui/components/page';
 10â†’import { Text } from '@airlock-cloud/management-ui/components/text';
 11â†’import { Title } from '@airlock-cloud/management-ui/components/title';
 12â†’import ConfigurationActionGroup from '@airlock-cloud/management-ui/features/config-wizard/ConfigurationActionGroup';
 13â†’import OperationActionGroup from '@airlock-cloud/management-ui/features/config-wizard/OperationActionGroup';
 14â†’import Forbidden from '@airlock-cloud/management-ui/features/errors/Forbidden';
 15â†’import { useRequiredTenantId } from '@airlock-cloud/management-ui/features/tenants/base/use-tenant-id/useTenantId';
 16â†’import { PublicPathBuilder } from '@airlock-cloud/management-ui/pages/public.routes';
 17â†’
 18â†’function GettingStartedPage() {
 19â†’	const { t } = useTranslation();
 20â†’	const tenantId = useRequiredTenantId();
 21â†’	const { data: tenant } = useTenant(tenantId);
 22â†’	const navigate = useNavigate();
 23â†’	const previousTenantId = useRef(tenantId);
 24â†’	const recommendations = t('pages.configuration.gettingStarted.recommendation.list', {
 25â†’		returnObjects: true,
 26â†’		defaultValue: ['Adjust settings below where appropriate', 'Activate and test your tenant'],
 27â†’	}) as string[];
 28â†’
 29â†’	useEffect(() => {
 30â†’		if (tenantId !== previousTenantId.current && !tenant.isWizardEnabled) {
 31â†’			navigate(new PublicPathBuilder().appRoutes().configuration().tenants().tenantId(tenantId).build());
 32â†’		}
 33â†’		previousTenantId.current = tenantId;
 34â†’	}, [tenant.isWizardEnabled, tenantId, navigate, previousTenantId]);
 35â†’
 36â†’	if (!tenant.isWizardEnabled) {
 37â†’		return <Forbidden />;
 38â†’	}
 39â†’
 40â†’	return (
 41â†’		<Page>
 42â†’			<Page.Head
 43â†’				title={t('pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.title', {
 44â†’					defaultValue: 'Getting started',
 45â†’				})}
 46â†’			>
 47â†’				<Text>
 48â†’					{t('pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.description', {
 49â†’						defaultValue: 'Start and test a configuration within minutes',
 50â†’					})}
 51â†’				</Text>
 52â†’			</Page.Head>
 53â†’			<Page.Section>
 54â†’				<InfoZone icon={ThumbUpIcon}>
 55â†’					<InfoZone.Head>
 56â†’						{t(
 57â†’							'pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.recommendation.title',
 58â†’							{
 59â†’								defaultValue: 'Recommended workflow',
 60â†’							}
 61â†’						)}
 62â†’					</InfoZone.Head>
 63â†’					<InfoZone.Body>
 64â†’						<ol className="list-inside list-decimal">
 65â†’							{recommendations.map((recommendation, index) => (
 66â†’								<li key={index}>{recommendation}</li>
 67â†’							))}
 68â†’							<li>
 69â†’								<Trans
 70â†’									t={t}
 71â†’									i18nKey="pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.recommendation.list.reachOut"
 72â†’								>
 73â†’									<EmbeddedLink target="_blank" href="https://jira.airlock.com">
 74â†’										Reach out to our team
 75â†’									</EmbeddedLink>{' '}
 76â†’									for help fine-tuning the configuration
 77â†’								</Trans>
 78â†’							</li>
 79â†’						</ol>
 80â†’					</InfoZone.Body>
 81â†’				</InfoZone>
 82â†’			</Page.Section>
 83â†’			<Page.Section>
 84â†’				<Title order={2}>
 85â†’					{t(
 86â†’						'pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.configuration.section.title',
 87â†’						{ defaultValue: 'Configuration' }
 88â†’					)}
 89â†’				</Title>
 90â†’				<ConfigurationActionGroup />
 91â†’			</Page.Section>
 92â†’			<Page.Section>
 93â†’				<Title order={2}>
 94â†’					{t('pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.operation.section.title', {
 95â†’						defaultValue: 'Operation',
 96â†’					})}
 97â†’				</Title>
 98â†’				<OperationActionGroup />
 99â†’			</Page.Section>
100â†’		</Page>
101â†’	);
102â†’}
103â†’
104â†’export default GettingStartedPage;
105â†’

  1â†’import React, { useState } from 'react';
  2â†’import { useTranslation } from 'react-i18next';
  3â†’
  4â†’import { ActionGroup } from '@airlock-cloud/management-ui/components/action-group';
  5â†’import { ApplicationType } from '@airlock-cloud/management-ui/domain/application';
  6â†’import { BrandingType } from '@airlock-cloud/management-ui/domain/uiCustomization';
  7â†’import { UserOnboardingType } from '@airlock-cloud/management-ui/domain/userOnboarding';
  8â†’import ApplicationSettingsModal from '@airlock-cloud/management-ui/features/config-wizard/modals/ApplicationSettingsModal';
  9â†’import AuthenticationSettingsModal from '@airlock-cloud/management-ui/features/config-wizard/modals/AuthenticationSettingsModal';
 10â†’import UserOnboardingModal from '@airlock-cloud/management-ui/features/config-wizard/modals/UserOnboardingModal';
 11â†’import useSaasConfig from '@airlock-cloud/management-ui/features/config-wizard/use-saas-config/useSaasConfig';
 12â†’import { useRequiredTenantId } from '@airlock-cloud/management-ui/features/tenants/base/use-tenant-id/useTenantId';
 13â†’
 14â†’import UserExperienceSettingsModal from './modals/UserExperienceSettingsModal';
 15â†’
 16â†’function ConfigurationActionGroup() {
 17â†’	const { t } = useTranslation();
 18â†’
 19â†’	const tenantId = useRequiredTenantId();
 20â†’	const { data: saasConfig } = useSaasConfig(tenantId);
 21â†’	const [isAuthenticationSettingsModalOpen, setIsAuthenticationSettingsModalOpen] = useState(false);
 22â†’	const [isApplicationSettingsModalOpen, setIsApplicationSettingsModalOpen] = useState(false);
 23â†’	const [isUserOnboardingModalOpen, setUserOnboardingModalOpen] = useState(false);
 24â†’	const [isUserExperienceSettingsModalOpen, setIsUserExperienceSettingsModalOpen] = useState(false);
 25â†’
 26â†’	const authenticationLabel = saasConfig.authentication.usePasskey
 27â†’		? t('features.configuration.wizard.configuration.actions.authentication.passKey.label', {
 28â†’				defaultValue: 'Passwordless',
 29â†’			})
 30â†’		: saasConfig.authentication.emailOtp
 31â†’			? t('features.configuration.wizard.configuration.actions.authentication.otp.label', {
 32â†’					defaultValue: 'Username, Password and Email OTP',
 33â†’				})
 34â†’			: t('features.configuration.wizard.configuration.actions.authentication.password.label', {
 35â†’					defaultValue: 'Username and Password',
 36â†’				});
 37â†’
 38â†’	const applicationLabel =
 39â†’		saasConfig.application.type === ApplicationType.PORTAL_APPLICATION
 40â†’			? t('features.configuration.wizard.configuration.actions.app.portal.label', {
 41â†’					defaultValue: 'Not configured',
 42â†’				})
 43â†’			: saasConfig.application.oidcApplication?.name;
 44â†’
 45â†’	const userOnboardingLabel =
 46â†’		saasConfig.userOnboarding.type === UserOnboardingType.MANUAL_ACCOUNT_CREATION
 47â†’			? t('features.configuration.wizard.configuration.actions.accounts.manual.label', {
 48â†’					defaultValue: 'An administrator',
 49â†’				})
 50â†’			: t('features.configuration.wizard.configuration.actions.accounts.selfRegistration.label', {
 51â†’					defaultValue: 'User by self-registration',
 52â†’				});
 53â†’
 54â†’	const brandingLabel =
 55â†’		saasConfig.uiCustomization.type === BrandingType.DEFAULT
 56â†’			? t('features.configuration.wizard.configuration.actions.branding.default.label', {
 57â†’					defaultValue: 'Default branding',
 58â†’				})
 59â†’			: t('features.configuration.wizard.configuration.actions.branding.custom.label', {
 60â†’					defaultValue: 'Custom branding',
 61â†’				});
 62â†’
 63â†’	return (
 64â†’		<>
 65â†’			<div className="mt-2">
 66â†’				<ActionGroup>
 67â†’					<ActionGroup.Item
 68â†’						icon={{ icon: 1 }}
 69â†’						title={t('features.configuration.wizard.configuration.actions.app.title', {
 70â†’							defaultValue: 'Application',
 71â†’						})}
 72â†’						subtitle={t('features.configuration.wizard.configuration.actions.app.subtitle', {
 73â†’							defaultValue: 'Where do users land after login?',
 74â†’						})}
 75â†’						actionPreview={applicationLabel}
 76â†’						action={() => setIsApplicationSettingsModalOpen(true)}
 77â†’					/>
 78â†’					<ActionGroup.Item
 79â†’						icon={{ icon: 2 }}
 80â†’						title={t('features.configuration.wizard.configuration.actions.authentication.title', {
 81â†’							defaultValue: 'Authentication flow',
 82â†’						})}
 83â†’						subtitle={t('features.configuration.wizard.configuration.actions.authentication.subtitle', {
 84â†’							defaultValue: 'How will your users authenticate?',
 85â†’						})}
 86â†’						actionPreview={authenticationLabel}
 87â†’						action={() => setIsAuthenticationSettingsModalOpen(true)}
 88â†’					/>
 89â†’					<ActionGroup.Item
 90â†’						icon={{ icon: 3 }}
 91â†’						title={t('features.configuration.wizard.configuration.actions.accounts.title', {
 92â†’							defaultValue: 'User onboarding',
 93â†’						})}
 94â†’						subtitle={t('features.configuration.wizard.configuration.actions.accounts.subtitle', {
 95â†’							defaultValue: 'Who will create user accounts?',
 96â†’						})}
 97â†’						actionPreview={userOnboardingLabel}
 98â†’						action={() => setUserOnboardingModalOpen(true)}
 99â†’					/>
100â†’					<ActionGroup.Item
101â†’						icon={{ icon: 4 }}
102â†’						title={t('features.configuration.wizard.configuration.actions.ux.title', {
103â†’							defaultValue: 'User experience',
104â†’						})}
105â†’						subtitle={t('features.configuration.wizard.configuration.actions.ux.subtitle', {
106â†’							defaultValue: 'What will the UI look like?',
107â†’						})}
108â†’						actionPreview={brandingLabel}
109â†’						action={() => setIsUserExperienceSettingsModalOpen(true)}
110â†’					/>
111â†’				</ActionGroup>
112â†’			</div>
113â†’
114â†’			<ApplicationSettingsModal
115â†’				isOpen={isApplicationSettingsModalOpen}
116â†’				close={() => setIsApplicationSettingsModalOpen(false)}
117â†’			/>
118â†’
119â†’			<AuthenticationSettingsModal
120â†’				isOpen={isAuthenticationSettingsModalOpen}
121â†’				close={() => setIsAuthenticationSettingsModalOpen(false)}
122â†’			/>
123â†’
124â†’			<UserOnboardingModal isOpen={isUserOnboardingModalOpen} close={() => setUserOnboardingModalOpen(false)} />
125â†’
126â†’			<UserExperienceSettingsModal
127â†’				isOpen={isUserExperienceSettingsModalOpen}
128â†’				close={() => setIsUserExperienceSettingsModalOpen(false)}
129â†’			/>
130â†’		</>
131â†’	);
132â†’}
133â†’
134â†’export default ConfigurationActionGroup;
135â†’

  1â†’import GroupIcon from '@airlock/material-symbols/svg/outlined/group.svg';
  2â†’import LoginIcon from '@airlock/material-symbols/svg/outlined/login.svg';
  3â†’import React, { useEffect, useRef, useState } from 'react';
  4â†’import { useTranslation } from 'react-i18next';
  5â†’
  6â†’import { FEATURE_FLAG_CREATE_USER_IN_TENANT } from '@airlock-cloud/management-ui/common/featureFlags';
  7â†’import usePolledMostRecentConfigActivation from '@airlock-cloud/management-ui/common/use-config-activation/usePolledMostRecentConfigActivation';
  8â†’import usePolledTenantDeployment from '@airlock-cloud/management-ui/common/use-polled-tenant-deployment/usePolledTenantDeployment';
  9â†’import useSetNotification from '@airlock-cloud/management-ui/common/use-set-notification/useSetNotification';
 10â†’import { ActionGroup } from '@airlock-cloud/management-ui/components/action-group';
 11â†’import EmbeddedPanel from '@airlock-cloud/management-ui/components/embedded-panel/EmbeddedPanel';
 12â†’import {
 13â†’	ConfigActivation,
 14â†’	ConfigActivationStatus,
 15â†’	isConfigActivationOngoing,
 16â†’} from '@airlock-cloud/management-ui/domain/configActivation';
 17â†’import {
 18â†’	canLoginappBeOpened,
 19â†’	hasAdminappMtlsEnabled,
 20â†’	hasDeployment,
 21â†’	hasLoginUrl,
 22â†’	isDeploymentAvailable,
 23â†’} from '@airlock-cloud/management-ui/domain/tenantDeployment';
 24â†’import DeploymentActionGroupItem from '@airlock-cloud/management-ui/features/config-wizard/DeploymentActionGroupItem';
 25â†’import CreateTestUserModal from '@airlock-cloud/management-ui/features/config-wizard/modals/CreateTestUserModal';
 26â†’import { useRequiredTenantId } from '@airlock-cloud/management-ui/features/tenants/base/use-tenant-id/useTenantId';
 27â†’import { PublicPathBuilder } from '@airlock-cloud/management-ui/pages/public.routes';
 28â†’
 29â†’function OperationActionGroup() {
 30â†’	const { t } = useTranslation();
 31â†’	const tenantId = useRequiredTenantId();
 32â†’	const setNotification = useSetNotification();
 33â†’
 34â†’	const [isCreateTestUserModalOpen, setCreateTestUserModalOpen] = useState(false);
 35â†’
 36â†’	const { data: deployment } = usePolledTenantDeployment(tenantId);
 37â†’	const polledMostRecentActivation = usePolledMostRecentConfigActivation(tenantId);
 38â†’
 39â†’	const adminappUrl = `${import.meta.env.VITE_BASE_PATH}${new PublicPathBuilder().tenantIAMRedirect().build({ tenantId })}`;
 40â†’	// RejectedInvalidConfig and RejectedUnsupportedVersion should not occur
 41â†’	// when configurations are created via the Getting Started guide
 42â†’	const hasMostRecentActivationFailed =
 43â†’		polledMostRecentActivation?.status === ConfigActivationStatus.Failed ||
 44â†’		polledMostRecentActivation?.status === ConfigActivationStatus.RejectedInvalidConfig ||
 45â†’		polledMostRecentActivation?.status === ConfigActivationStatus.RejectedUnsupportedVersion;
 46â†’	const isActivating = !!polledMostRecentActivation && isConfigActivationOngoing(polledMostRecentActivation);
 47â†’
 48â†’	const isCreateTestUserDisabled =
 49â†’		!isDeploymentAvailable(deployment) || hasAdminappMtlsEnabled(deployment) || !FEATURE_FLAG_CREATE_USER_IN_TENANT;
 50â†’
 51â†’	const previousActivationRef = useRef<ConfigActivation | null>(null);
 52â†’	useEffect(() => {
 53â†’		const previousActivation = previousActivationRef.current;
 54â†’		const wasActivating = !!previousActivation && isConfigActivationOngoing(previousActivation);
 55â†’
 56â†’		if (wasActivating && !isActivating && polledMostRecentActivation?.status === ConfigActivationStatus.Success) {
 57â†’			setNotification({
 58â†’				level: 'success',
 59â†’				message: t('features.configuration.wizard.operation.deployment.result.success', {
 60â†’					defaultValue: 'Activation was successful',
 61â†’				}),
 62â†’			});
 63â†’		}
 64â†’		if (wasActivating && hasMostRecentActivationFailed) {
 65â†’			setNotification({
 66â†’				level: 'error',
 67â†’				message: t('features.configuration.wizard.operation.deployment.result.failure', {
 68â†’					defaultValue: 'Activation failed',
 69â†’				}),
 70â†’			});
 71â†’		}
 72â†’
 73â†’		previousActivationRef.current = polledMostRecentActivation;
 74â†’	}, [polledMostRecentActivation?.status]);
 75â†’
 76â†’	const errorPanelMessage = hasDeployment(deployment)
 77â†’		? t('features.configuration.wizard.operation.deployment.failure.panel.withDeployment.description', {
 78â†’				defaultValue:
 79â†’					"We couldn't activate your tenant. It is still running with the most recent valid configuration.",
 80â†’			})
 81â†’		: t('features.configuration.wizard.operation.deployment.failure.panel.withoutDeployment.description', {
 82â†’				defaultValue: "We couldn't activate your tenant.",
 83â†’			});
 84â†’
 85â†’	const createCreateTestUserTooltipLabel = (): string | undefined => {
 86â†’		if (!FEATURE_FLAG_CREATE_USER_IN_TENANT) {
 87â†’			return t(
 88â†’				'features.configuration.wizard.operation.userManagement.createTestUser.button.tooltipLabel.featureIsMissing',
 89â†’				{
 90â†’					defaultValue: 'This feature is currently not available.',
 91â†’				}
 92â†’			);
 93â†’		}
 94â†’		if (hasAdminappMtlsEnabled(deployment)) {
 95â†’			return t(
 96â†’				'features.configuration.wizard.operation.userManagement.createTestUser.button.tooltipLabel.adminappMtlsConfigured',
 97â†’				{
 98â†’					defaultValue: 'Test users cannot be created if mTLS is configured for Adminapp',
 99â†’				}
100â†’			);
101â†’		}
102â†’		if (!isDeploymentAvailable(deployment)) {
103â†’			return t(
104â†’				'features.configuration.wizard.operation.userManagement.createTestUser.button.tooltipLabel.deploymentIsNotAvailable',
105â†’				{
106â†’					defaultValue: 'A test user can only be created once the deployment has become available.',
107â†’				}
108â†’			);
109â†’		}
110â†’		return undefined;
111â†’	};
112â†’
113â†’	return (
114â†’		<>
115â†’			<div className="mt-2 flex flex-col gap-2">
116â†’				{hasMostRecentActivationFailed ? (
117â†’					<EmbeddedPanel
118â†’						title={t('features.configuration.wizard.operation.deployment.failure.panel.title', {
119â†’							defaultValue: 'Failed activation',
120â†’						})}
121â†’						message={errorPanelMessage}
122â†’						level="error"
123â†’					/>
124â†’				) : null}
125â†’				<ActionGroup>
126â†’					<DeploymentActionGroupItem tenantId={tenantId} />
127â†’					<ActionGroup.Item
128â†’						icon={{ icon: LoginIcon, color: 'black' }}
129â†’						title={t('features.configuration.wizard.operation.loginForm.title', {
130â†’							defaultValue: 'Login form',
131â†’						})}
132â†’						subtitle={t('features.configuration.wizard.operation.loginForm.subtitle', {
133â†’							defaultValue: 'Open the login form to test logging in',
134â†’						})}
135â†’						link={
136â†’							hasLoginUrl(deployment)
137â†’								? {
138â†’										href: deployment.loginUrl,
139â†’										label: t('features.configuration.wizard.operation.loginForm.link.label', {
140â†’											defaultValue: 'Open login form',
141â†’										}),
142â†’									}
143â†’								: undefined
144â†’						}
145â†’						disabled={!canLoginappBeOpened(deployment)}
146â†’					/>
147â†’					<ActionGroup.Item
148â†’						icon={{ icon: GroupIcon, color: 'black' }}
149â†’						title={t('features.configuration.wizard.operation.userManagement.title', {
150â†’							defaultValue: 'User management',
151â†’						})}
152â†’						subtitle={t('features.configuration.wizard.operation.userManagement.subtitle', {
153â†’							defaultValue: 'Create and manage users',
154â†’						})}
155â†’						secondaryButton={{
156â†’							label: t(
157â†’								'features.configuration.wizard.operation.userManagement.createTestUser.button.label',
158â†’								{
159â†’									defaultValue: 'Create test user',
160â†’								}
161â†’							),
162â†’							tooltipLabel: createCreateTestUserTooltipLabel(),
163â†’							action: () => setCreateTestUserModalOpen(true),
164â†’							disabled: isCreateTestUserDisabled,
165â†’						}}
166â†’						link={{
167â†’							href: adminappUrl,
168â†’							label: t('features.configuration.wizard.operation.userManagement.link.label', {
169â†’								defaultValue: 'Manage users',
170â†’							}),
171â†’						}}
172â†’						disabled={!isDeploymentAvailable(deployment)}
173â†’					/>
174â†’				</ActionGroup>
175â†’			</div>
176â†’			<CreateTestUserModal isOpen={isCreateTestUserModalOpen} close={() => setCreateTestUserModalOpen(false)} />
177â†’		</>
178â†’	);
179â†’}
180â†’
181â†’export default OperationActionGroup;
182â†’

  1â†’import PendingIcon from '@airlock/material-symbols/svg/outlined/pending.svg';
  2â†’import PlayCircleIcon from '@airlock/material-symbols/svg/outlined/play_circle.svg';
  3â†’import RocketIcon from '@airlock/material-symbols/svg/outlined/rocket.svg';
  4â†’import RocketLaunchIcon from '@airlock/material-symbols/svg/outlined/rocket_launch.svg';
  5â†’import React, { useEffect } from 'react';
  6â†’import { useTranslation } from 'react-i18next';
  7â†’
  8â†’import { useTranslatableMessageJSONStringTranslations } from '@airlock-cloud/management-ui/common/error.utils';
  9â†’import { asTranslatableMessageJSONString } from '@airlock-cloud/management-ui/common/translatableMessage';
 10â†’import useAdminHasPermission from '@airlock-cloud/management-ui/common/use-admin-has-permission/useAdminHasPermission';
 11â†’import usePolledMostRecentConfigActivation from '@airlock-cloud/management-ui/common/use-config-activation/usePolledMostRecentConfigActivation';
 12â†’import usePolledTenantDeployment from '@airlock-cloud/management-ui/common/use-polled-tenant-deployment/usePolledTenantDeployment';
 13â†’import useSetErrorNotificationFromServerResponse from '@airlock-cloud/management-ui/common/use-set-notification/useSetErrorNotificationFromServerResponse';
 14â†’import useSetNotification from '@airlock-cloud/management-ui/common/use-set-notification/useSetNotification';
 15â†’import { ActionGroup } from '@airlock-cloud/management-ui/components/action-group';
 16â†’import { ActionGroupItemIconColor } from '@airlock-cloud/management-ui/components/action-group/ActionGroup';
 17â†’import {
 18â†’	ConfigActivationStatus,
 19â†’	isConfigActivationOngoing,
 20â†’} from '@airlock-cloud/management-ui/domain/configActivation';
 21â†’import { isDeploymentAvailable } from '@airlock-cloud/management-ui/domain/tenantDeployment';
 22â†’import useActivateSaasConfig from '@airlock-cloud/management-ui/features/config-wizard/use-activate-saas-config/useActivateSaasConfig';
 23â†’
 24â†’function DeploymentActionGroupItem({ tenantId }: DeploymentActionGroupItemProps) {
 25â†’	const { t } = useTranslation();
 26â†’	const { data: deployment } = usePolledTenantDeployment(tenantId);
 27â†’	const polledMostRecentActivation = usePolledMostRecentConfigActivation(tenantId);
 28â†’	const activateSaasConfig = useActivateSaasConfig();
 29â†’	const hasConfigActivatePermission = useAdminHasPermission('config.activate');
 30â†’	const submittedAtRef = React.useRef<number | null>(null);
 31â†’	const setNotification = useSetNotification();
 32â†’	const setErrorNotificationFromServerResponse = useSetErrorNotificationFromServerResponse();
 33â†’	const translateMessageJSONString = useTranslatableMessageJSONStringTranslations();
 34â†’	/**
 35â†’	 * `isActivating` requires the ConfigActivation to reload, which may take a brief moment, such that it may
 36â†’	 * seem to a user that the action was not submitted. To make sure the feedback appears immediately, we also
 37â†’	 * use `wasSubmitted` to keep track if the action was triggered and optimistically update the action button immediately.
 38â†’	 */
 39â†’	const [isSubmitting, setIsSubmitting] = React.useState(false);
 40â†’	const isActivating =
 41â†’		isSubmitting || (!!polledMostRecentActivation && isConfigActivationOngoing(polledMostRecentActivation));
 42â†’
 43â†’	/**
 44â†’	 * Make sure to reset the submitting state again so that the components are updated according to
 45â†’	 * the status of the config activation and deployment.
 46â†’	 */
 47â†’	useEffect(() => {
 48â†’		if (isSubmitting && polledMostRecentActivation?.activationDate) {
 49â†’			const activationTime = polledMostRecentActivation.activationDate.getTime();
 50â†’			if (submittedAtRef.current === null || activationTime > submittedAtRef.current) {
 51â†’				setIsSubmitting(false);
 52â†’			}
 53â†’		}
 54â†’	}, [polledMostRecentActivation?.activationDate]);
 55â†’
 56â†’	/**
 57â†’	 * Order matters! We want to display the activating state as soon as the activation is submitted
 58â†’	 * (and not only once the ConfigActivation update is retrieved) and thus check for this condition first.
 59â†’	 */
 60â†’	function getActivationState(): ActivationState {
 61â†’		if (isActivating) {
 62â†’			return DEPLOYMENT_STATES.Pending;
 63â†’		}
 64â†’		if (polledMostRecentActivation === null) {
 65â†’			return DEPLOYMENT_STATES.Inactive;
 66â†’		}
 67â†’		if (isDeploymentAvailable(deployment)) {
 68â†’			return DEPLOYMENT_STATES.Active;
 69â†’		}
 70â†’		// RejectedInvalidConfig and RejectedUnsupportedVersion should not occur
 71â†’		// when configurations are created via the Getting Started guide
 72â†’		if (
 73â†’			polledMostRecentActivation.status === ConfigActivationStatus.Failed ||
 74â†’			polledMostRecentActivation.status === ConfigActivationStatus.RejectedInvalidConfig ||
 75â†’			polledMostRecentActivation.status === ConfigActivationStatus.RejectedUnsupportedVersion
 76â†’		) {
 77â†’			return DEPLOYMENT_STATES.Inactive;
 78â†’		}
 79â†’		return DEPLOYMENT_STATES.Unavailable;
 80â†’	}
 81â†’
 82â†’	function getActivationIcon(): {
 83â†’		icon: string | number;
 84â†’		color?: ActionGroupItemIconColor;
 85â†’	} {
 86â†’		switch (getActivationState()) {
 87â†’			case DEPLOYMENT_STATES.Active:
 88â†’				return { icon: RocketLaunchIcon, color: 'green' };
 89â†’			case DEPLOYMENT_STATES.Inactive:
 90â†’				return { icon: RocketIcon };
 91â†’			case DEPLOYMENT_STATES.Pending:
 92â†’				return { icon: PendingIcon, color: 'blue' };
 93â†’			case DEPLOYMENT_STATES.Unavailable:
 94â†’				return { icon: PendingIcon, color: 'yellow' };
 95â†’		}
 96â†’	}
 97â†’
 98â†’	function getActivationTitle() {
