115â†’				});
116â†’		}
117â†’	}
118â†’
119â†’	function getActivationSubtitle() {
120â†’		switch (getActivationState()) {
121â†’			case DEPLOYMENT_STATES.Active:
122â†’				return t('features.configuration.wizard.operation.deployment.subtitle.success', {
123â†’					defaultValue: 'Your tenant is ready',
124â†’				});
125â†’			case DEPLOYMENT_STATES.Inactive:
126â†’				return t('features.configuration.wizard.operation.deployment.subtitle.inactive', {
127â†’					defaultValue: 'Activate tenant to enable login and user management',
128â†’				});
129â†’			case DEPLOYMENT_STATES.Pending:
130â†’				return t('features.configuration.wizard.operation.deployment.subtitle.pending', {
131â†’					defaultValue: 'This may take a few minutes',
132â†’				});
133â†’			case DEPLOYMENT_STATES.Unavailable:
134â†’				return t('features.configuration.wizard.operation.deployment.subtitle.unavailable', {
135â†’					defaultValue: 'Tenant cannot currently be reached',
136â†’				});
137â†’		}
138â†’	}
139â†’
140â†’	const handleSubmit = async () => {
141â†’		submittedAtRef.current = Date.now();
142â†’		setIsSubmitting(true);
143â†’		await activateSaasConfig(tenantId, {
144â†’			onError: (error) => {
145â†’				setIsSubmitting(false);
146â†’				// TODO ALSAAS-4330: this is a code duplicate from src/form/Form.tsx
147â†’				// TODO ALSAAS-4330: this should be moved into one of the error notification handlers.
148â†’				if (error.status && error.status !== 400) {
149â†’					setErrorNotificationFromServerResponse(error);
